import{_ as a,o as i,c as t,a4 as o}from"./chunks/framework.EG5hAXdg.js";const m=JSON.parse('{"title":"About finance","description":"This page gives on overview of financial management in HUNT Cloud.","frontmatter":{"title":"About finance","category":"HUNT Cloud","permalink":"/administer-science/start-here/finance","outline":0,"description":"This page gives on overview of financial management in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/finance.md","filePath":"administer-science/start-here/finance.md"}'),n={name:"administer-science/start-here/finance.md"};function r(s,e,l,c,d,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="about-finance" tabindex="-1">About finance <a class="header-anchor" href="#about-finance" aria-label="Permalink to &quot;About finance&quot;">​</a></h1><p><strong>This section covers budgeting, costs, bills and how to navigate our price list.</strong></p><p>When you spend your hard earned money well, science is happening. Such, we see money as a scientific enabler that you should master and use well.</p><nav class="table-of-contents"><ul><li><a href="#cost-elements">Cost elements</a></li><li><a href="#budgeting">Budgeting</a></li><li><a href="#invoicing">Invoicing</a></li><li><a href="#billing">Billing</a></li><li><a href="#start-small">Start small</a></li><li><a href="#read-more">Read more</a></li></ul></nav><p>And for the record, HUNT Cloud is part of a public university that runs these services with zero profit. Such, money is mean towards our goal of enabling more knowledge from sensitive data.</p><h3 id="cost-elements" tabindex="-1">Cost elements <a class="header-anchor" href="#cost-elements" aria-label="Permalink to &quot;Cost elements&quot;">​</a></h3><p>You pay for the resources you use on a daily bases. By default you pay for one machine and the amount of the storage they you have allocated in your lab. In addition, there is a yearly lab subscription cost that covers support and operations.</p><p>You can order as many additional machines and terabyte of storage as you like in our administer science service desk. These will be invoiced in according with our price list.</p><h3 id="budgeting" tabindex="-1">Budgeting <a class="header-anchor" href="#budgeting" aria-label="Permalink to &quot;Budgeting&quot;">​</a></h3><p>We have developed a price estimator and added price examples to our &quot;pricing&quot; section to guide your cost estimates (see link below).</p><p>However, it may still be difficult to translate your experiments into machine sizes and storage volumes. Such, don&#39;t hesitate to contact us for dialogues on cost estimates. We are more than happy to share our experience from similar activities in your field, and to help with estimated for grants and other funding sources.</p><h3 id="invoicing" tabindex="-1">Invoicing <a class="header-anchor" href="#invoicing" aria-label="Permalink to &quot;Invoicing&quot;">​</a></h3><p>You will receive an PDF with detailed invoice information per quarter. The invoice specifies the number of machines you have use, their sizes, the machine&#39;s daily cost and the quarters total machine cost. The invoice will also specify how many terabyte of storage you have had available in your lab for each day of the quarter, it&#39;s cost, and the quarters total storage cost.</p><h3 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h3><p>For us, this is the process of sending the actual bill. The process differ based on your organizational affiliation:</p><ul><li>Inside NTNU: The transaction is handled as an internal transfer, and and money are transferred directly from your account to our account.</li><li>Outside NTNU: The actual bill is sent from NTNU&#39;s billing system directly to your organizations billing system.</li></ul><h3 id="start-small" tabindex="-1">Start small <a class="header-anchor" href="#start-small" aria-label="Permalink to &quot;Start small&quot;">​</a></h3><p>Our advice is to start with a small lab configuration and quickly increase capacity when all your magic ingredients are in place.</p><p>It is not uncommon that it takes longer that anticipated to get your scientific project up to full speed, for example if hiring processes or data deliveries takes longer than expected.</p><p>Don&#39;t overdo storage. Overspending by overestimating storage needs early in your project period is frustrating. Start with a small volume, and increase the size as soon a data is read to be transferred.</p><p>Quickly get into the habit of downgrading or turning off comput resources in down-periods. Research activities are difficult to schedule, especially in large groups. However, it is cost effective to adjust your machine sizes based on actual needs, for example reduce sizes during holidays or writing periods.</p><h3 id="read-more" tabindex="-1">Read more <a class="header-anchor" href="#read-more" aria-label="Permalink to &quot;Read more&quot;">​</a></h3><ul><li><a href="/administer-science/prices/">Pricing</a></li></ul>',23)])])}const p=a(n,[["render",r]]);export{m as __pageData,p as default};
